"use strict";
({ params, imports }) => {
  const programEncounter = params.entity;
  const moment = imports.moment;
  const scheduleBuilder = new imports.rulesConfig.VisitScheduleBuilder({programEncounter});

  if(true){
    const earliestDate = moment(programEncounter.encounterDateTime).add(30, 'days').toDate();
    const maxDate = moment(programEncounter.encounterDateTime).add(45, 'days').toDate();
    scheduleBuilder.add({name: "ANC", encounterType: "ANC", earliestDate, maxDate});  
}

  return scheduleBuilder.getAll();
};

'use strict';
({params, imports}) => {
  const programEncounter = params.entity;
  const moment = imports.moment;
  const formElement = params.formElement;
  const _ = imports.lodash;
  let visibility = true;
  let value = null;
  let answersToSkip = [];
  let answers = [];
  let validationErrors = [];

  const encounterType = programEncounter.encounterType.name;
  console.log('encounterType--->',encounterType);

  const lastEncounters = programEncounter.programEnrolment
    .getEncountersOfType(encounterType, true)
    .filter(enc =>
      enc.encounterDateTime &&
      programEncounter.encounterDateTime && moment(programEncounter.encounterDateTime).isAfter(moment(enc.encounterDateTime))
    );

  const visitNumberUUID = 'e528a7ec-6b78-4692-b593-1b63b7c11194';

  console.log(lastEncounters.length);

  if (lastEncounters.length > 0) {
    answers = lastEncounters
      .map(enc => enc.getObservationValue(visitNumberUUID))
      .filter(val => val);
    console.log('answers--->',answers);
  }
  console.log('answers (UUIDs)--->', answers);

  _.forEach(answers, (answer) => {
      const answerToSkip = formElement.getAnswerWithConceptUuid(answer);
      console.log('answerToSkip--->',answerToSkip);
      if (answerToSkip) answersToSkip.push(answerToSkip);
  });


  return new imports.rulesConfig.FormElementStatus(formElement.uuid, visibility, value, answersToSkip, validationErrors);
};

