'use strict';
({ params, imports }) => {
  const programEncounter = params.entity;
  const moment = imports.moment;
  const formElement = params.formElement;
  const _ = imports.lodash;

  let visibility = true;
  let value = null;
  let answersToSkip = [];
  let validationErrors = [];

  const ancVisitNo = programEncounter.getObservationReadableValue('Visit Number');

  if (ancVisitNo === '1st') {
    visibility = false;
    return new imports.rulesConfig.FormElementStatus(formElement.uuid, visibility, value, answersToSkip, validationErrors);
  }

  const encounterType = programEncounter.encounterType.name;

  const previousEncounters = programEncounter.programEnrolment
    .getEncountersOfType(encounterType, true)
    .filter(enc =>
      enc.encounterDateTime &&
      programEncounter.encounterDateTime &&
      moment(programEncounter.encounterDateTime)
        .isAfter(moment(enc.encounterDateTime))
    )
    .sort((a, b) => moment(b.encounterDateTime).diff(moment(a.encounterDateTime)));

  const HB_UUID = '561d9364-7a0d-4649-9c61-32da2d2c7a94';

  const currentHB = parseFloat(
    programEncounter.getObservationReadableValue(HB_UUID)
  );

  if (!isNaN(currentHB) && previousEncounters.length > 0) {
    const lastEncounter = previousEncounters[0];
    const lastHB = parseFloat(
      lastEncounter.getObservationReadableValue(HB_UUID)
    );
    if (!isNaN(lastHB)) {
      if (currentHB > lastHB) {
        value = 'Yes';
      } else if (currentHB < lastHB) {
        value = 'No';
      } else {
        value = 'Same as last ANC';
      }
    }
  }

  return new imports.rulesConfig.FormElementStatus(formElement.uuid, visibility, value, answersToSkip, validationErrors);
};

