  const condition12 = new imports.rulesConfig.RuleCondition({programEnrolment, formElement}).when.valueInEnrolment("8546fb24-996f-4d30-a1eb-e397dad87f76").greaterThanOrEqualTo(1000).and.when.valueInEnrolment("8546fb24-996f-4d30-a1eb-e397dad87f76").lessThan(1500).matches();

