'use strict';
({ params, imports }) => {
  const programEncounter = params.entity;
  const moment = imports.moment;
  const formElement = params.formElement;

  let visibility = true;
  let value = null;
  let answersToSkip = [];
  let validationErrors = [];

  const LMPObs = programEncounter.programEnrolment
    .getObservationValue("9200ce99-8da4-4b83-950f-be8e5cfc5e0e");

  const deliveryDateObs = programEncounter
    .getObservationValue("6a0252e3-a671-4b70-a1e7-9ebeded85188");

  const lmpDate = moment(LMPObs);
  const deliveryDate = moment(deliveryDateObs);

  const isLmpValid =
    lmpDate && lmpDate.toDate && !isNaN(lmpDate.toDate().getTime());

  const isDeliveryValid =
    deliveryDate && deliveryDate.toDate && !isNaN(deliveryDate.toDate().getTime());

  if (isLmpValid && isDeliveryValid) {
    value = deliveryDate.diff(lmpDate, 'weeks');
  }

  return new imports.rulesConfig.FormElementStatus(formElement.uuid, visibility, value, answersToSkip, validationErrors);
};

