'use strict';
({params, imports}) => {
  const programEncounter = params.entity;
  const moment = imports.moment;
  const formElement = params.formElement;
  const _ = imports.lodash;
  let visibility = true;
  let value = null;
  let answersToSkip = [];
  let validationErrors = [];

  const condition11 = new imports.rulesConfig.RuleCondition({programEncounter, formElement}).when.valueInEncounter("cd77cb7a-842e-418a-8dec-c4f7030e594f").greaterThan(0).matches();

  visibility = condition11 ;

  if(visibility){
    const noOfChildDelivered = parseFloat(programEncounter.getObservationReadableValue('cd77cb7a-842e-418a-8dec-c4f7030e594f'));

    console.log('noOfChildDelivered--->',noOfChildDelivered);

    const childrenDetails = programEncounter.getObservationValue('8449a749-a977-4f74-af99-ccfc14749693');

    console.log('childrenDetails--->',childrenDetails);

    let activeGroupCount = 0;

    if (Array.isArray(childrenDetails)) {
      console.log('in array if');
      activeGroupCount = childrenDetails.filter(child => {
        if (!child || typeof child !== 'object') return false;

        return Object.values(child).some(value => value !== undefined && value !== null && value !== '');
      }).length;
    }
    console.log('activeGroupCount--->',activeGroupCount);

    if (!isNaN(noOfChildDelivered) && activeGroupCount > noOfChildDelivered) {
      validationErrors.push("Repeatable Question Groups should not exceed the total number of Delivered child/children.");
    } else if (!isNaN(noOfChildDelivered) && activeGroupCount < noOfChildDelivered) {
      validationErrors.push("Repeatable Question Groups should not less than the total number of Delivered child/children.");
    }
  }

  return new imports.rulesConfig.FormElementStatus(formElement.uuid, visibility, value, answersToSkip, validationErrors);
};

