'use strict';
({params, imports}) => {
    const programEncounter = params.entity;
    const individual = programEncounter.programEnrolment.individual;
    const asOnDate = programEncounter.encounterDateTime;
    const moment = imports.moment;
    const formElement = params.formElement;
    const _ = imports.lodash;
    let visibility = false;
    let value = null;
    let answersToSkip = [];
    let validationErrors = [];

    const weight = programEncounter.getObservationValue('Weight');
    const height = programEncounter.getObservationValue('Height');

    function getNutritionStatus(zScore) {
        if(zScore < -3) {
            return 'Severe Acute Malnutrition (SAM)';
        } else if(zScore >= -3 && zScore < -2) {
            return 'Moderate Acute Malnutrition (MAM)';
        } else if(zScore >= -2 && zScore <= 2) {
            return 'Normal';
        } else if(zScore > 2 && zScore <= 3) {
            return 'Overweight';
        }
        else if(zScore > 3){
            return 'Obese';
        }
        return 'Unknown';
    }

    if(weight && height) {
        visibility = true;
        const zScoresForChild = ruleServiceLibraryInterfaceForSharingModules.common.getZScore(individual, asOnDate, weight, height);

        console.log('zScoreForChild--->', zScoresForChild);

        const zScore = zScoresForChild.wfh;

        value = getNutritionStatus(zScore);
    }

    return new imports.rulesConfig.FormElementStatus(formElement.uuid, visibility, value, answersToSkip, validationErrors);
};

